# Generated by google (gemini-2.5-flash)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'IMAGE_NAME', defaultValue: 'my-app', description: 'The name of the Docker image (e.g., my-service)')
        string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'The tag for the Docker image (e.g., v1.0.0, latest, build-${BUILD_NUMBER})')
        string(name: 'REGISTRY_URL', defaultValue: 'myregistry.example.com/myorg', description: 'The URL of the Docker registry (e.g., myregistry.example.com/myorg or docker.io/myusername)')
        string(name: 'DOCKERFILE_CONTEXT', defaultValue: '.', description: 'The build context path for the Dockerfile (e.g., . or app/)')
    }

    stages {
        stage('Checkout') {
            steps {
                // Replace with your SCM details (e.g., Git, SVN)
                // This example assumes your Dockerfile and source code are in the repository root
                git branch: 'main', url: 'https://github.com/your-org/your-repo.git'
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
                    echo "Building Docker image: ${fullImageName} from context: ${params.DOCKERFILE_CONTEXT}"
                    sh "docker build -t ${fullImageName} ${params.DOCKERFILE_CONTEXT}"
                }
            }
        }

        stage('Push Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
                    echo "Pushing Docker image: ${fullImageName}"
                    // IMPORTANT: Ensure your Jenkins agent has Docker configured and is logged into the registry.
                    // For private registries, you might need a `docker login` step or use `withRegistry` from Docker Pipeline plugin.
                    // Example for `withRegistry` (requires Docker Pipeline plugin and a Jenkins credential ID):
                    // docker.withRegistry("https://${params.REGISTRY_URL}", 'your-docker-credential-id') {
                    //     sh "docker push ${fullImageName}"
                    // }
                    sh "docker push ${fullImageName}"
                }
            }
        }
    }

    post {
        always {
            cleanWs() // Clean up workspace after build
        }
        success {
            echo 'Docker image build and push completed successfully!'
        }
        failure {
            echo 'Docker image build and push failed!'
        }
    }
}